public class ReviewsController : Controller
{
    private readonly ApplicationDbContext _context;

    public ReviewsController(ApplicationDbContext context)
    {
        _context = context;
    }

    public IActionResult ProductReviews(int productId)
    {
        var reviews = _context.Reviews
            .Where(r => r.ProductId == productId)
            .ToList();

        return View(reviews);
    }

    [HttpPost]
    public IActionResult SubmitReview(Review review)
    {
        if (ModelState.IsValid)
        {
            _context.Reviews.Add(review);
            _context.SaveChanges();
            return RedirectToAction("ProductReviews", new { productId = review.ProductId });
        }
        return View(review);
    }
}

@model IEnumerable<Review>

<h2>Product Reviews</h2>

@foreach (var review in Model)
{
    <div class="review">
        <h4>@Html.DisplayFor(m => review.UserName)</h4>
        <p>@Html.Raw(review.Content)</p>
    </div>
}

<form asp-action="SubmitReview" method="post">
    <input type="hidden" name="ProductId" value="@Model.First().ProductId" />
